/// <summary>
/// Class <c>ETGSPAINNumberSequenceModuleInventoryLoadJob</c> is responsible for loading
/// the inventory number sequences in the ETGSPAIN module.
/// </summary>
internal final class ETGSPAINNumberSequenceModuleInventoryLoadJob
{
}

Method.Source:
/// <summary>
/// Entry point for the class. This method is called when a menu item is selected
/// or when this class is set as the startup class in the system.
/// </summary>
/// <param name="_args">The arguments passed to the method.</param>
public static void main(Args _args)
{
    NumberSeqModuleInventory numberSeqModuleInventory = new NumberSeqModuleInventory();
    numberSeqModuleInventory.load();
}
